import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as e,a as s}from"./app-543248b1.js";const i={},a=s('<h1 id="网络安全" tabindex="-1"><a class="header-anchor" href="#网络安全" aria-hidden="true">#</a> 网络安全</h1><p>安全性：信息泄漏</p><p>认证试卷出处：双钥</p><p>流转试卷是否被篡改：MD5完整性</p><p>谁能审批试卷的身份认证：公钥与私钥</p><p>身份认证，角色：</p><ul><li>教师（出卷）</li><li>系主任（审批）</li><li>院长（审批）</li><li>文印</li></ul><p>流程：用户注册的时候，本地生产一对公钥和私钥、私钥直接下载，自己保存，公钥上传服务器，试卷表：</p><table><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>id</td><td>int</td><td>主键</td></tr><tr><td>name</td><td>varchar</td><td>试卷名称</td></tr><tr><td>filePath</td><td>varchar</td><td>存储路径</td></tr><tr><td>teacherId</td><td>int</td><td>出卷人</td></tr><tr><td>departmentHeadId</td><td>int</td><td>系主任id</td></tr><tr><td>deanId</td><td>int</td><td>院长id</td></tr><tr><td>status</td><td>int</td><td>状态 -1未通过审核 0-待审核 1-通过1级审核 2-通过2级审核</td></tr><tr><td>signature</td><td>varchar</td><td>签名</td></tr><tr><td>other</td><td>varchar</td><td>保留</td></tr></tbody></table><p>上传试卷：</p><ol><li>出卷人：使用下一个审核人的公钥加密试卷（本地加密）</li><li>审核人1：使用自己的私钥解密，更新审核信息，然后使用下一个人的公钥加密，</li><li>审核人2：使用自己的私钥解密，完成审核</li></ol><p>数字签名的实现步骤如下:</p><ol><li>试卷上传时,出卷人使用自己的私钥对试卷数据进行签名,生成数字签名。</li><li>在后续的审核流程中,每个审核人都可以使用出卷人的公钥验证数字签名,确保试卷数据未被篡改。</li><li>最终,院长审批通过后,可以在试卷信息中保存数字签名,以供后续使用时验证。</li></ol><p>数据库文件加密（路径）：</p><ul><li>采用对称加密</li></ul><p>需要修改的功能：</p><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-0"> 前端生成公钥私钥</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-1"> 注册接口增加公钥进去</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-2"> 审核状态添加字典</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-3"> 数据库生成</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-4" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-4"> 角色分配</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-5" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-5"> 前端页面生成</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-6" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-6"> 查询所有的系主任</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-7" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-7"> 查询所有的院长</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-8" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-8"> 修改系主任和院长为下拉列表</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-9" disabled="disabled"><label class="task-list-item-label" for="task-item-9"> 上传试卷，本地先用下一个人的公钥加密</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-10" disabled="disabled"><label class="task-list-item-label" for="task-item-10"> 上传之后，生成数字签名（本地签名，私钥签名 ）</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-11" disabled="disabled"><label class="task-list-item-label" for="task-item-11"> 私钥解密文件</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-12" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-12"> 更新审核状态接口</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-13" checked="checked" disabled="disabled"><label class="task-list-item-label" for="task-item-13"> 用户审核接口</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-14" disabled="disabled"><label class="task-list-item-label" for="task-item-14"> 存储路径加密接口</label></li></ul>',17),d=[a];function c(k,b){return l(),e("div",null,d)}const o=t(i,[["render",c],["__file","网络安全.html.vue"]]);export{o as default};
